--#region src/Util/Signal.lua
local Signal = {}
Signal.__index = Signal

function Signal.new()
	return setmetatable({
		_bindable = Instance.new("BindableEvent"),
		_destroyed = false,
	}, Signal)
end

function Signal:Connect(callback)
	assert(not self._destroyed, "Cannot connect to a destroyed Signal")
	assert(type(callback) == "function", "Signal callback must be a function")
	return self._bindable.Event:Connect(callback)
end

function Signal:Once(callback)
	local connection
	connection = self:Connect(function(...)
		connection:Disconnect()
		callback(...)
	end)
	return connection
end

function Signal:Fire(...)
	if not self._destroyed then
		self._bindable:Fire(...)
	end
end

function Signal:Wait()
	assert(not self._destroyed, "Cannot wait on a destroyed Signal")
	return self._bindable.Event:Wait()
end

function Signal:Destroy()
	if self._destroyed then
		return
	end
	self._destroyed = true
	self._bindable:Destroy()
end
--#endregion src/Util/Signal.lua

--#region src/Util/Maid.lua
local Maid = {}
Maid.__index = Maid

function Maid.new()
	return setmetatable({ _tasks = {}, _destroyed = false }, Maid)
end

function Maid:Give(taskValue)
	if taskValue == nil then
		return nil
	end
	if self._destroyed then
		self:_clean(taskValue)
		return taskValue
	end
	table.insert(self._tasks, taskValue)
	return taskValue
end

function Maid:_clean(taskValue)
	local kind = typeof(taskValue)
	if kind == "RBXScriptConnection" then
		taskValue:Disconnect()
	elseif kind == "Instance" then
		taskValue:Destroy()
	elseif type(taskValue) == "function" then
		taskValue()
	elseif type(taskValue) == "table" then
		if type(taskValue.Destroy) == "function" then
			taskValue:Destroy()
		elseif type(taskValue.Disconnect) == "function" then
			taskValue:Disconnect()
		end
	end
end

function Maid:Cleanup()
	for index = #self._tasks, 1, -1 do
		local taskValue = self._tasks[index]
		self._tasks[index] = nil
		local ok, message = pcall(function()
			self:_clean(taskValue)
		end)
		if not ok then
			warn("[Lotus] Cleanup error: " .. tostring(message))
		end
	end
end

function Maid:Destroy()
	if self._destroyed then
		return
	end
	self._destroyed = true
	self:Cleanup()
end
--#endregion src/Util/Maid.lua

--#region src/Util/Tween.lua
local Motion = {}

Motion.Fast = TweenInfo.new(0.14, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
Motion.Normal = TweenInfo.new(0.22, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
Motion.Slow = TweenInfo.new(0.42, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)

function Motion.tween(instance, tweenInfo, properties)
	if not instance or not instance.Parent then
		return nil
	end
	local tween = TweenService:Create(instance, tweenInfo or Motion.Normal, properties)
	tween:Play()
	return tween
end

function Motion.press(button, scale)
	local uiScale = create("UIScale", { Scale = 1, Parent = button })
	local maid = Maid.new()
	maid:Give(button.MouseButton1Down:Connect(function()
		Motion.tween(uiScale, Motion.Fast, { Scale = scale or 0.97 })
	end))
	maid:Give(button.MouseButton1Up:Connect(function()
		Motion.tween(uiScale, Motion.Fast, { Scale = 1 })
	end))
	maid:Give(button.MouseLeave:Connect(function()
		Motion.tween(uiScale, Motion.Fast, { Scale = 1 })
	end))
	return maid
end
--#endregion src/Util/Tween.lua

